module shift_reg(
    input clk,
    input rst,
    input [7:0] d,
    input load,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 8'b0;
        else if (load)
            q <= d;
        else
            q <= {q[6:0], 1'b0};  // Shift left
    end

endmodule
